import './tailwind.css';

const favIconPath = isDevelopment() ? '/favicon.png' : '/uiv2/favicon.png';

export const PublicActionPageConfirmation = () => {
  const params = useParams();
  const [searchParams] = useSearchParams();
  const langCode = searchParams.get('lang') ?? 'en';
  const { t } = useTranslation('common');
  const [submissions, setSubmissions] = useState<PublicSubmission[] | undefined>(undefined);
  const data = useMemo(() => submissions?.[0], [submissions]);
  const { actionPage } = useShowActionPage({
    accountSlug: data?.account?.slug,
    actionPageSlug: data?.actionPage?.slug,
  });

  // Add favicon to the page
  useEffect(() => {
    const favIconUrl =
      actionPage?.favIcon?.file?.small?.url ||
      actionPage?.account.favIcon?.file?.small?.url ||
      favIconPath;
    const favIconElement = document.getElementById('favicon');

    (favIconElement as HTMLLinkElement).href = favIconUrl;
  }, [actionPage]);

  useEffect(() => {
    const promises = params.submissionId
      ?.split(',')
      .map((submissionId) => getPublicSubmission({ submissionId }));

    if (!promises) {
      return;
    }

    Promise.all(promises)
      .then((results) => setSubmissions(results))
      .catch(() => {
        setSubmissions([]);
      });
  }, [params.submissionId]);

  const videoBlock = useMemo(() => {
    const isVideo = (block: ActionPageContentBlock): block is ActionPageContentBlockVideo =>
      block.type === 'video';

    return (
      data?.actionPage?.pageType === 'event' &&
      data?.actionPage?.content?.find(isVideo)?.content?.url
    );
  }, [data?.actionPage?.content, data?.actionPage?.pageType]);

  useEffect(() => {
    if (videoBlock) {
      useActionPageStore.setState(() => ({ content: data?.actionPage?.content }));
    }
  }, [data?.actionPage?.content, videoBlock]);

  const { data: headerImage } = useGetImage({
    imageId: data?.actionPage.confirmationConfiguration.headerImageId,
  });

  const { data: brandImage } = useGetImage({
    imageId: data?.account?.imageId,
  });

  const pageTitle = useMemo(
    () => (data?.actionPage?.seoTitle ? data?.actionPage?.seoTitle : t('receipt')),
    [t, data?.actionPage?.seoTitle]
  );

  const { customFieldResponses } = useSubmissionReceipt(data);

  const isPending = useMemo(
    () =>
      isDonationPage(data?.actionPage?.pageType) &&
      data?.captureAt === null &&
      data?.captured === false,
    [data?.actionPage?.pageType, data?.captureAt, data?.captured]
  );

  if (!submissions) {
    return (
      <Flex alignItems="center" flexGrow={1} height="100%" justifyContent="center" width="100%">
        <Loading />
      </Flex>
    );
  }

  if (!data) {
    return (
      <Flex alignItems="center" flexGrow={1} height="100%" justifyContent="center" width="100%">
        <Heading>{t('couldNotFindReceipt')}</Heading>
      </Flex>
    );
  }

  const fundDisclaimers = (submissions ?? [])
    .flatMap((submission) => submission?.amountAllocationsAttributes ?? [])
    .map((allocation) => {
      const fund = actionPage?.fundConfiguration?.fundSelectionsAttributes?.find(
        (fnd) => fnd?.fund?.id === allocation?.actionPagesFund?.id
      );

      const disclaimer = fund?.fund?.translationsAttributes?.find(
        (translation) => translation?.languageIsoCode === langCode
      )?.disclaimer;

      return disclaimer ? { disclaimer, position: fund?.position ?? 0 } : null;
    })
    .filter((item) => item !== null)
    .sort((a, b) => (a?.position ?? 0) - (b?.position ?? 0))
    .map((item) => item!.disclaimer);

  return (
    <>
      <Helmet>
        <title>{pageTitle}</title>
      </Helmet>
      <Box backgroundColor="neutral.200" flexGrow={1} height="100%" overflowY="scroll">
        <Flex flexDirection="column" gap={10} maxW="640px" mx="auto" width="100%">
          <Box
            backgroundColor="white"
            borderRadius={{ base: 0, md: '16px' }}
            gap={10}
            mt={{ base: 0, md: 16 }}
            px={{ base: 4, md: 10 }}
            shadow="card"
          >
            {isPending && <PendingNotice />}
            <WorkflowsHeader
              accountName={data.account.displayName}
              actionElementColorPrimary={
                data.actionPage.designConfiguration.actionElementColorPrimary
              }
              image={headerImage ?? brandImage}
              isEditable={false}
            />
            {!!videoBlock && (
              <div className="my-4 aspect-video w-full" id="featured-video-container" />
            )}
            {submissions.map((submission) => (
              <SubmissionReceipt
                account={submission.account}
                aceProductSelections={submission.aceProductSelections}
                amountAllocations={(submission.amountAllocationsAttributes ?? []).map((x) => ({
                  accountId: x.actionPagesFund.accountId,
                  accountName: x.actionPagesFund.accountName,
                  actionPagesFundId: x.actionPagesFund.id ?? '',
                  amount: x.amount,
                  fundName: x.actionPagesFund?.name ?? '',
                  fundType: x.fundType ?? x.actionPagesFund?.type ?? '',
                }))}
                customFieldResponses={customFieldResponses}
                employerAddress={submission.employerAddressAttributes}
                employerName={submission.employerName}
                eventTickets={submission.eventTickets}
                fees={getSubmissionFees(submission)}
                firstName={submission.firstName}
                frequency={
                  submission.scheduleAttributes
                    ? commitmentScheduleToFrequency(submission.scheduleAttributes)
                    : SourceFrequency.Once
                }
                giftOfAnyAmountProduct={
                  (submission.products ?? []).length > 0 ? submission.products[0] : undefined
                }
                isConfirmationPage
                key={submission.id}
                lastName={submission.lastName}
                middleName={submission.middleName}
                nextChargeDate={
                  (submission?.scheduleAttributes?.upcomingDates ?? []).length > 0
                    ? new Date(submission?.scheduleAttributes!.upcomingDates![0] ?? '')
                    : undefined
                }
                occupation={submission.occupation}
                organization={submission.organization}
                pageType={submission.actionPage.pageType}
                paymentMethod={submission.paymentMethod}
                phone={submission.phone}
                promoCode={submission.promoCode}
                promoCodeBreakdown={submission.promoCodeBreakdown}
                receiptId={submission.id}
                receiptTextBlock={
                  (
                    submission?.actionPage.confirmationConfiguration.content?.find(
                      (x) => x.type === 'text'
                    )?.content as ActionPageContentBlockTextContent
                  )?.text
                }
                storefrontProductSelections={submission.storefrontProductSelections}
                submissionDate={
                  submission.createdAt
                    ? formatDate(new Date(submission.createdAt), 'ShortDate')
                    : undefined
                }
                submissionEmail={submission.email}
                suffix={submission.suffix}
                title={submission.title}
                {...submission.addressAttributes}
              />
            ))}
          </Box>
          <WorkflowsFooter
            footerDisclaimer={data.actionPage.confirmationConfiguration.footerDisclaimer}
            fundDisclaimers={fundDisclaimers}
          />
        </Flex>
      </Box>
    </>
  );
};

export default PublicActionPageConfirmation;

